#pragma once

// Second-order contractions of the LISREL map, shared by the analytic
// observed-information paths:
//
//   • inference.cpp — complete-data `information_observed_analytic`, with
//     weight G = Σ⁻¹ − Σ⁻¹SΣ⁻¹,
//   • fiml.cpp      — analytic observed FIML Hessian, with G the
//     pattern-aggregated moment-gradient weight.
//
// `second_sigma_trace` evaluates tr(G · ∂²Σ/∂θ_a∂θ_b) case-by-case on the
// (mat_a, mat_b) pair, including the reduced-form Λ/Ψ/Β cross-terms; pairs
// with vanishing second derivative (anything involving Θ or ν, Ψ-Ψ, α-α)
// return zero. `second_mu` is the matching ∂²μ/∂θ_a∂θ_b for the mean map
// μ = ν + Λ(I−B)⁻¹α. Both take parameters located in the SAME block; callers
// gate on `ParamLocation::block` before calling.

#include <Eigen/Core>

#include "magmaan/model/model_evaluator.hpp"

namespace magmaan::detail {

// Products of the symmetric weight G with the assembled block matrices that
// every (a, b) pair reuses; build once per block.
struct SecondOrderWeights {
  Eigen::MatrixXd G;        // symmetric p × p weight
  Eigen::MatrixXd GLamA;    // G · ΛA
  Eigen::MatrixXd GLamMid;  // G · Λ · Mid
  Eigen::MatrixXd P;        // (ΛA)ᵀ · G · (ΛA)
  Eigen::MatrixXd MKA;      // Mid · (Λᵀ G Λ) · A
  Eigen::VectorXd A_alpha;  // A·α; empty when no mean structure or no α

  static SecondOrderWeights build(Eigen::MatrixXd weight,
                                  const model::BlockMatrices& bm,
                                  bool has_means) {
    SecondOrderWeights out;
    out.G = std::move(weight);
    out.GLamA.noalias()   = out.G * bm.LamA;
    out.GLamMid.noalias() = (out.G * bm.Lambda) * bm.Mid;
    const Eigen::MatrixXd K = bm.Lambda.transpose() * out.G * bm.Lambda;
    out.P.noalias()   = bm.LamA.transpose() * out.G * bm.LamA;
    out.MKA.noalias() = bm.Mid * K * bm.A;
    if (has_means && bm.Alpha.size() > 0 && bm.A.rows() > 0) {
      out.A_alpha.noalias() = bm.A * bm.Alpha;
    }
    return out;
  }
};

inline double h2_lambda_lambda(const model::ParamLocation& la,
                               const model::ParamLocation& lb,
                               const Eigen::MatrixXd& Mid,
                               const Eigen::MatrixXd& G) noexcept {
  return 2.0 * Mid(la.col, lb.col) * G(la.row, lb.row);
}

inline double h2_lambda_psi(const model::ParamLocation& lam,
                            const model::ParamLocation& psi,
                            const Eigen::MatrixXd& GLamA,
                            const Eigen::MatrixXd& A) noexcept {
  if (psi.row == psi.col) {
    return 2.0 * GLamA(lam.row, psi.row) * A(lam.col, psi.row);
  }
  return 2.0 * (GLamA(lam.row, psi.row) * A(lam.col, psi.col) +
                GLamA(lam.row, psi.col) * A(lam.col, psi.row));
}

inline double h2_lambda_beta(const model::ParamLocation& lam,
                             const model::ParamLocation& beta,
                             const Eigen::MatrixXd& GLamA,
                             const Eigen::MatrixXd& GLamMid,
                             const Eigen::MatrixXd& Mid,
                             const Eigen::MatrixXd& A) noexcept {
  return 2.0 * (GLamA(lam.row, beta.row)    * Mid(beta.col, lam.col) +
                GLamMid(lam.row, beta.col)  * A(lam.col, beta.row));
}

inline double h2_psi_beta(const model::ParamLocation& psi,
                          const model::ParamLocation& beta,
                          const Eigen::MatrixXd& P,
                          const Eigen::MatrixXd& A) noexcept {
  if (psi.row == psi.col) {
    return 2.0 * P(psi.row, beta.row) * A(beta.col, psi.row);
  }
  return 2.0 * (P(psi.col, beta.row) * A(beta.col, psi.row) +
                P(psi.row, beta.row) * A(beta.col, psi.col));
}

inline double h2_beta_beta(const model::ParamLocation& ba,
                           const model::ParamLocation& bb,
                           const Eigen::MatrixXd& A,
                           const Eigen::MatrixXd& MKA,
                           const Eigen::MatrixXd& P,
                           const Eigen::MatrixXd& Mid) noexcept {
  return 2.0 * (A(bb.col, ba.row) * MKA(ba.col, bb.row) +
                A(ba.col, bb.row) * MKA(bb.col, ba.row) +
                Mid(ba.col, bb.col) * P(ba.row, bb.row));
}

// tr(G · ∂²Σ/∂θ_a∂θ_b) for two free parameters in the same block.
inline double second_sigma_trace(const model::ParamLocation& la,
                                 const model::ParamLocation& lb,
                                 const SecondOrderWeights& w,
                                 const model::BlockMatrices& bm) noexcept {
  using model::MatId;
  switch (la.mat) {
    case MatId::Lambda:
      switch (lb.mat) {
        case MatId::Lambda: return h2_lambda_lambda(la, lb, bm.Mid, w.G);
        case MatId::Psi:    return h2_lambda_psi(la, lb, w.GLamA, bm.A);
        case MatId::Beta:   return h2_lambda_beta(la, lb, w.GLamA, w.GLamMid,
                                                  bm.Mid, bm.A);
        default:            return 0.0;
      }
    case MatId::Psi:
      switch (lb.mat) {
        case MatId::Lambda: return h2_lambda_psi(lb, la, w.GLamA, bm.A);
        case MatId::Beta:   return h2_psi_beta(la, lb, w.P, bm.A);
        default:            return 0.0;
      }
    case MatId::Beta:
      switch (lb.mat) {
        case MatId::Lambda: return h2_lambda_beta(lb, la, w.GLamA, w.GLamMid,
                                                  bm.Mid, bm.A);
        case MatId::Psi:    return h2_psi_beta(lb, la, w.P, bm.A);
        case MatId::Beta:   return h2_beta_beta(la, lb, bm.A, w.MKA, w.P,
                                                bm.Mid);
        default:            return 0.0;
      }
    default:
      return 0.0;
  }
}

// ∂²μ/∂θ_a∂θ_b of μ = ν + ΛAα; zero vector for pairs that do not touch the
// mean map's curvature (only Λ-α, Λ-Β, α-Β, Β-Β are nonzero).
inline Eigen::VectorXd second_mu(const model::ParamLocation& a,
                                 const model::ParamLocation& b,
                                 const model::BlockMatrices& bm,
                                 const Eigen::VectorXd& A_alpha) {
  const Eigen::Index p = bm.Lambda.rows();
  Eigen::VectorXd out = Eigen::VectorXd::Zero(p);
  using model::MatId;

  auto lambda_alpha = [&](const model::ParamLocation& lam,
                          const model::ParamLocation& alpha) {
    if (bm.A.rows() == 0) return;
    out(static_cast<Eigen::Index>(lam.row)) =
        bm.A(static_cast<Eigen::Index>(lam.col),
             static_cast<Eigen::Index>(alpha.row));
  };
  auto lambda_beta = [&](const model::ParamLocation& lam,
                         const model::ParamLocation& beta) {
    if (A_alpha.size() == 0) return;
    out(static_cast<Eigen::Index>(lam.row)) =
        bm.A(static_cast<Eigen::Index>(lam.col),
             static_cast<Eigen::Index>(beta.row)) *
        A_alpha(static_cast<Eigen::Index>(beta.col));
  };
  auto alpha_beta = [&](const model::ParamLocation& alpha,
                        const model::ParamLocation& beta) {
    out.noalias() =
        bm.LamA.col(static_cast<Eigen::Index>(beta.row)) *
        bm.A(static_cast<Eigen::Index>(beta.col),
             static_cast<Eigen::Index>(alpha.row));
  };
  auto beta_beta = [&](const model::ParamLocation& ba,
                       const model::ParamLocation& bb) {
    if (A_alpha.size() == 0) return;
    out.noalias() =
        bm.LamA.col(static_cast<Eigen::Index>(bb.row)) *
        bm.A(static_cast<Eigen::Index>(bb.col),
             static_cast<Eigen::Index>(ba.row)) *
        A_alpha(static_cast<Eigen::Index>(ba.col));
    out.noalias() +=
        bm.LamA.col(static_cast<Eigen::Index>(ba.row)) *
        bm.A(static_cast<Eigen::Index>(ba.col),
             static_cast<Eigen::Index>(bb.row)) *
        A_alpha(static_cast<Eigen::Index>(bb.col));
  };

  switch (a.mat) {
    case MatId::Lambda:
      if (b.mat == MatId::Alpha) lambda_alpha(a, b);
      else if (b.mat == MatId::Beta) lambda_beta(a, b);
      break;
    case MatId::Alpha:
      if (b.mat == MatId::Lambda) lambda_alpha(b, a);
      else if (b.mat == MatId::Beta) alpha_beta(a, b);
      break;
    case MatId::Beta:
      if (b.mat == MatId::Lambda) lambda_beta(b, a);
      else if (b.mat == MatId::Alpha) alpha_beta(b, a);
      else if (b.mat == MatId::Beta) beta_beta(a, b);
      break;
    case MatId::Theta:
    case MatId::Psi:
    case MatId::Nu:
      break;
  }
  return out;
}

}  // namespace magmaan::detail
